WITH MEMBER [Measures].[Combined Gross Margin] AS
    Aggregate(
        {
            [Sales Channel].[Sales Channel].&[Online],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Gross Margin]
    )
SELECT {[Measures].[Combined Gross Margin]} ON COLUMNS
FROM [Adventure Works]

